type AppEnv = Record<string, string | undefined>;

const env = import.meta.env;

const appDomain = env.MOTIVATION_APP_DOMAIN ?? 'motivation.tiesnoordhuis.nl';
const devHost = env.MOTIVATION_DEV_HOST ?? 'localhost';
const localApiPort = env.MOTIVATION_API_PORT_LOCAL ?? '3001';
const remoteApiHost = env.MOTIVATION_API_HOST_REMOTE ?? '192.168.178.170';
const remoteApiPort = env.MOTIVATION_API_PORT_REMOTE ?? '3000';
const piGatewayHost = env.MOTIVATION_PI_GATEWAY_HOST ?? '192.168.178.18';
const piGatewayPort = env.MOTIVATION_PI_GATEWAY_PORT ?? '3000';
const hcBridgeHost = env.MOTIVATION_HC_BRIDGE_HOST ?? '127.0.0.1';
const hcBridgePort = env.MOTIVATION_HC_BRIDGE_PORT ?? '47653';

function buildOrigin(protocol: 'http' | 'https', host: string, port?: string): string {
    return port ? `${protocol}://${host}:${port}` : `${protocol}://${host}`;
}

const previewPort = env.MOTIVATION_PREVIEW_PORT ?? '4173';

const currentHostname = self.location?.hostname ?? '';
const currentPort = self.location?.port ?? '';

/**
 * Detection logic for local development environment.
 * Robust against port changes and supports local network (mobile) testing.
 */
export const isLocal = (!!import.meta.env.DEV || currentPort === previewPort) && (
    currentHostname === 'localhost' ||
    currentHostname === '127.0.0.1' ||
    currentHostname === devHost ||
    currentHostname === remoteApiHost
);

/**
 * Strict builds (test / isolated-instance builds set MOTIVATION_API_STRICT=1)
 * must never silently fall back to the remote/prod origin: a served-port or
 * hostname mismatch means the build is misconfigured, and quietly pointing it
 * at the production backend would read — or worse, mutate — real data.
 * Fail loud instead (story 183, spike 182 §3.1).
 */
if (env.MOTIVATION_API_STRICT === '1' && !isLocal) {
    throw new Error(
        `[config] MOTIVATION_API_STRICT build refused to fall back to the remote API origin ` +
        `(${buildOrigin('http', remoteApiHost, remoteApiPort)}). ` +
        `Served from hostname "${currentHostname}" port "${currentPort}" but this build expects ` +
        `preview port "${previewPort}" (MOTIVATION_PREVIEW_PORT) on localhost/127.0.0.1/` +
        `"${devHost}"/"${remoteApiHost}". Serve the build on its compiled origin or rebuild ` +
        `with matching MOTIVATION_PREVIEW_PORT / MOTIVATION_API_PORT_LOCAL.`,
    );
}

export const APP_ORIGINS = {
    production: {
        http: buildOrigin('http', appDomain),
        https: buildOrigin('https', appDomain),
    },
};

/**
 * API URL used for all backend requests.
 * In local mode, it dynamically uses the current hostname to support mobile/IP-based testing.
 */
export const API_URL = isLocal
    ? buildOrigin('http', currentHostname, localApiPort)
    : buildOrigin('http', remoteApiHost, remoteApiPort);

/**
 * Pi gateway — always-on Raspberry Pi on the local network.
 * Shared host and port values are sourced from the repository root `.env`.
 */
export const PI_GATEWAY_URL = buildOrigin('http', piGatewayHost, piGatewayPort);

/**
 * Health Connect bridge (story 250) — the sideloaded reader app serving HC
 * data on device loopback. Overridable (story 257) so isolated test-instance
 * builds can point it at the mock stub's published port; the prod default is
 * the bridge app's fixed loopback origin.
 */
export const HC_BRIDGE_URL = buildOrigin('http', hcBridgeHost, hcBridgePort);

/**
 * Build identifier, set per build by tooling that needs to tell two deploys
 * apart (the story-212 lifecycle harness builds twice with differing stamps —
 * which also forces this chunk's hash, and transitively the app entry's, to
 * diverge between the builds). Production builds are simply 'unstamped'.
 */
export const BUILD_STAMP: string = env.VITE_BUILD_STAMP ?? 'unstamped';

console.debug('[SYNC-DEBUG][config] Resolved config:', {
    isLocal,
    API_URL,
    hostname: currentHostname,
    port: currentPort,
    DEV: import.meta.env.DEV,
    previewPort,
    remoteApiHost,
    localApiPort,
    buildStamp: BUILD_STAMP,
});
